import network
import machine
import time
import json
from microcoapy import CoapServer, CoapResource, CoapRequest, CoapResponse
from microcoapy.coap import COAP_GET, COAP_PUT, COAP_CONTENT, COAP_205

# WiFi connection
def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    wlan.connect('your_wifi_ssid', 'your_wifi_password')
    while not wlan.isconnected():
        time.sleep(1)
    return wlan

# Sensor and actuator data
sensor_data = {'temp': 25.0}
actuator_data = {'light': False}

# Resource handlers
class TempResource(CoapResource):
    def __init__(self):
        super().__init__('/sensors/temp')
    
    def get(self, request):
        response = CoapResponse(COAP_205)
        response.set_content_type(COAP_CONTENT.TEXT_PLAIN)
        response.set_payload(str(sensor_data['temp']))
        return response
    
    def put(self, request):
        try:
            payload = request.get_payload().decode()
            sensor_data['temp'] = float(payload)
            response = CoapResponse(COAP_204)
            return response
        except:
            response = CoapResponse(COAP_400)
            return response

class LightResource(CoapResource):
    def __init__(self):
        super().__init__('/actuators/light')
    
    def get(self, request):
        response = CoapResponse(COAP_205)
        response.set_content_type(COAP_CONTENT.TEXT_PLAIN)
        response.set_payload(str(actuator_data['light']).lower())
        return response
    
    def put(self, request):
        try:
            payload = request.get_payload().decode().lower()
            actuator_data['light'] = payload in ('true', '1', 'on')
            response = CoapResponse(COAP_204)
            return response
        except:
            response = CoapResponse(COAP_400)
            return response

# Main server setup
def main():
    # Connect to WiFi
    wlan = connect_wifi()
    print("Connected to WiFi")
    
    # Create CoAP server
    server = CoapServer()
    
    # Add resources
    server.add_resource(TempResource())
    server.add_resource(LightResource())
    
    # Start server
    server.start()
    
    print("CoAP server started on", wlan.ifconfig()[0])
    
    # Main loop
    while True:
        try:
            server.handle_request()
            time.sleep(0.01)
        except Exception as e:
            print("Error:", e)
            time.sleep(1)

if __name__ == "__main__":
    main()